function CourseList(props) {
  return (
    <div>
      <h2>Danh sách khóa học</h2>

      {props.courses.map((c, index) => (
        <div key={index}>
          {c}
          <button onClick={() => props.onDelete(index)}>
            Xóa
          </button>
        </div>
      ))}
    </div>
  );
}

export default CourseList;
